openscad:
case_dia = 40; // [20:1:80]
case_h = 7; // [3:0.5:15]
dial_dia = 34; // [15:1:70]
bezel_h = 1.5; // [0.5:0.5:4]
marker_w = 1.2; // [0.5:0.2:3]
marker_len = 3; // [1:0.5:6]
hand_w = 1.8; // [0.8:0.2:4]
hour_len = 9; // [5:0.5:18]
min_len = 13; // [6:0.5:20]
$fn = 60;
module watch() {
  color("black")
  difference() {
    cylinder(h=case_h, d=case_dia, center=true);
    translate([0,0,bezel_h]) cylinder(h=case_h, d=dial_dia+4, center=true);
  }
  color("white")
  translate([0,0,bezel_h-0.1]) cylinder(h=case_h-bezel_h+0.2, d=dial_dia, center=true);
  color("red")
  for(i=[0:11]) {
    rotate([0,0,i*30])
    translate([0,dial_dia/2-marker_len/2-1,bezel_h+1.5])
    cube([marker_w,marker_len,2],center=true);
  }
  color("red") {
    translate([0,0,bezel_h+2.5])
    rotate([0,0,300])
    cube([hand_w,hour_len,1.5],center=true);
    translate([0,0,bezel_h+2.5])
    rotate([0,0,20])
    cube([hand_w,min_len,1.5],center=true);
  }
}
watch();
